      // Reset form
      setFormData({
        sourceNetwork: '',
        sourceToken: '',
        destinationNetwork: '',
        destinationToken: '',
        amount: '',
        destinationAddress: '',
        reward: '0',
      });

      // Show success message
      setErrors({ success: 'Transfer initiated successfully! Check your transaction hash.' });

    } catch (error) {
      console.error('Transfer failed:', error);
      setErrors({ general: error.message });
    } finally {
      setIsLoading(false);
