    const testCases = [
      { amount: '1.0', balance: '10.0', expected: true },
      { amount: '10.0', balance: '10.0', expected: true },
      { amount: '10.1', balance: '10.0', expected: false },
      { amount: '0.001', balance: '0.001', expected: true },
